function eggDoneness(method,t,opts){const ez=KIN.egg_zones;if(!ez)return null;opts=opts||{};const T0=opts.T0!=null?opts.T0:(opts.startFrom==="room"?KIN.start_temp_C.room:KIN.start_temp_C.fridge),Tenv=kinEnv(opts.env?opts.env:methodHeatEnv(method)),Tw=tempAt(t,T0,Tenv,ez.white.tau_min),Ty=tempAt(t,T0,Tenv,ez.yolk.tau_min),Th=ez.yolk.thresholds_C,white=Tw>=ez.white.set_C?"set":"liquid",yolk=Ty<Th.jammy?"runny":Ty<Th.medium?"jammy":Ty<Th.hard?"medium":"hard",overall=yolk==="hard"?"hard-boiled":yolk==="medium"?"medium-boiled":yolk==="jammy"?"soft-boiled (jammy)":"very soft";return{T_white:+Tw.toFixed(1),T_yolk:+Ty.toFixed(1),white,yolk,overall};}
function eggZoneSamples(method,dur,n,opts){const ez=KIN.egg_zones;if(!ez)return[];n=n||Math.max(2,Math.min(120,dur));opts=opts||{};const pts=[];for(let i=0;i<=n;i++){const t=dur*i/n,dn=eggDoneness(method,t,opts);pts.push({t:+t.toFixed(1),T_white:dn.T_white,T_yolk:dn.T_yolk});}return pts;}
