function bestFitPacks(need,sizes){if(need<=0)return{packs:[],total:0,leftover:0};sizes=sizes.slice().sort((a,b)=>b-a);let best=null;const cap=Math.ceil(need/Math.min(...sizes))+1;const rec=(i,c,t)=>{if(t>=need){const lo=t-need,n=c.reduce((a,b)=>a+b,0);if(!best||lo<best.leftover||(lo===best.leftover&&n<best.n))best={counts:c.slice(),total:t,leftover:lo,n};return;}if(i>=sizes.length)return;for(let x=0;x<=cap;x++){c[i]=x;rec(i+1,c,t+x*sizes[i]);if(t+x*sizes[i]>need+Math.max(...sizes))break;}c[i]=0;};rec(0,new Array(sizes.length).fill(0),0);const packs=[];best.counts.forEach((x,i)=>{for(let j=0;j<x;j++)packs.push(sizes[i]);});return{packs,total:best.total,leftover:best.leftover};}
function planDemand(plan,lib){const d={};plan.forEach(({recipeId,day})=>{const r=lib[recipeId];if(!r)return;r.ingredients.forEach(it=>{const c=toCanonical(it.k,it.qty,it.u||it.unit);if(!d[it.k])d[it.k]={qty:0,first:Infinity};d[it.k].qty+=c;d[it.k].first=Math.min(d[it.k].first,day);});});return d;}
function productionLots(plan,lib){const out=[];plan.forEach(({recipeId,day})=>{const r=lib[recipeId];if(r&&r.yields)r.yields.forEach(y=>out.push({id:"prod_"+recipeId+"_"+y.k,k:y.k,qty:y.qty,bought:day,sellBy:day+CATALOG[y.k].keep,opened:null,loc:"fridge",produced:true}));});return out;}
function shoppingList(plan,inv,lib){const dem=planDemand(plan,lib),pool=inv.concat(productionLots(plan,lib)),out=[];Object.keys(dem).forEach(k=>{const need=dem[k].qty,first=dem[k].first,I=CATALOG[k];const good=pool.filter(l=>l.k===k&&effExpiry(l)>=first);const avail=good.reduce((a,l)=>a+l.qty,0);const short=Math.max(0,need-avail);let buy;if(short<=0)buy={kind:"none"};else if(I.produced)buy={kind:"short_produced"};else if(isPackaged(k)){const bf=bestFitPacks(short,I.packs);buy={kind:"packs",packs:bf.packs,leftover:+bf.leftover.toFixed(1)};}else{let q=short;q=I.regime==="count"?Math.ceil(q):Math.ceil(q/50)*50;buy={kind:"loose",qty:q};}const fromLeftover=good.some(l=>l.produced);const timing=I.produced?{when:"from_kitchen"}:(I.keep<PERISH?{when:"perishable",buyAfter:Math.max(0,first-(I.keep-1)),buyBy:first}:{when:"anytime"});out.push({k,name:I.name,group:I.group,need:+need.toFixed(1),unit:I.unit,avail:+avail.toFixed(1),shortfall:+short.toFixed(1),packaged:isPackaged(k),produced:!!I.produced,fromLeftover,buy,timing});});return out.sort((a,b)=>a.name.localeCompare(b.name));}
function useItUp(plan,inv,lib){const fn={},dem=planDemand(plan,lib);Object.keys(dem).forEach(k=>fn[k]=dem[k].first);return inv.map(l=>({...l,name:CATALOG[l.k].name,unit:CATALOG[l.k].unit,expiry:effExpiry(l),atRisk:(fn[l.k]==null)||(effExpiry(l)<fn[l.k])})).sort((a,b)=>a.expiry-b.expiry);}
// storage capacity (litres)
const VOL=KD.vol;
const LOCATIONS=KD.seed.locations;
const volOf=k=>VOL[k]!=null?VOL[k]:0.001, defaultLoc=k=>CATALOG[k].group==="pantry"?"pantry":"fridge", lotVol=l=>l.qty*volOf(l.k);
function storageLoad(inv){const L={fridge:0,freezer:0,pantry:0};inv.forEach(l=>{const loc=l.loc||defaultLoc(l.k);L[loc]=(L[loc]||0)+lotVol(l);});Object.keys(L).forEach(k=>L[k]=+L[k].toFixed(1));return L;}
function fitsCheck(inv,buys){const L=storageLoad(inv);(buys||[]).forEach(b=>{const loc=defaultLoc(b.k);L[loc]=+(L[loc]+b.qty*volOf(b.k)).toFixed(1);});const over={};Object.keys(LOCATIONS).forEach(loc=>{if(L[loc]>LOCATIONS[loc].cap)over[loc]=+(L[loc]-LOCATIONS[loc].cap).toFixed(1);});return{load:L,over};}
function buysFromShopping(sl){const out=[];sl.forEach(r=>{if(r.buy.kind==="loose")out.push({k:r.k,qty:r.buy.qty});else if(r.buy.kind==="packs")out.push({k:r.k,qty:r.buy.packs.reduce((a,b)=>a+b,0)});});return out;}
function cookSchedule(plan,lib){return plan.slice().sort((a,b)=>a.day-b.day).map(({recipeId,day})=>{const r=lib[recipeId];if(!r)return null;const st=topoSteps(recipeGraph(r));return{day,recipeId,name:r.name,steps:st,hands:st.filter(s=>s.active).reduce((a,s)=>a+s.dur,0),passive:st.filter(s=>!s.active).reduce((a,s)=>a+s.dur,0)};}).filter(Boolean);}
function planWaste(plan,inv,lib){const streams={};plan.forEach(({recipeId})=>{const r=lib[recipeId];if(!r)return;recipeGraph(r).procs.forEach(p=>(p.waste||[]).forEach(w=>streams[w]=(streams[w]||0)+1));});const fn={},dem=planDemand(plan,lib);Object.keys(dem).forEach(k=>fn[k]=dem[k].first);const spoil=inv.filter(l=>{const e=effExpiry(l);return(fn[l.k]==null)||(e<fn[l.k]);}).map(l=>({name:CATALOG[l.k].name,qty:l.qty,unit:CATALOG[l.k].unit,expiry:effExpiry(l)}));return{streams:Object.keys(streams),spoil};}
function exportRecipe(r){const g=recipeGraph(r);return{name:r.name,keep:r.keep,method:r.method||"moist",ingredients:r.ingredients,states:Object.fromEntries(Object.entries(g.states).map(([k,v])=>[k,{kind:v.kind,keep:v.keep}])),steps:topoSteps(g).map(p=>({title:p.title,trans:p.trans,active:!!p.active,dur:p.dur,in:p.consumes,out:p.produces,waste:p.waste||[]}))};}
// nutrition (per canonical unit — seeded estimates)
const NUTR=KD.nutr;
function recipeNutrition(recipe){const t={kcal:0,p:0,c:0,f:0};recipe.ingredients.forEach(it=>{const n=NUTR[it.k];if(!n)return;const q=toCanonical(it.k,it.qty,it.u||it.unit);t.kcal+=n.kcal*q;t.p+=n.p*q;t.c+=n.c*q;t.f+=n.f*q;});Object.keys(t).forEach(k=>t[k]=Math.round(t[k]));return t;}
